1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter~\ref{chap:Genus}, with genus $g = g(C)$.
5	
6	Because the Picard-scheme machinery (Chapter~\ref{chap:Picard_Functor}) is blocked at the level of \lstinline{MonoidalCategory X.Modules} and the full FGA representability theorem, this chapter builds the Jacobian by an alternative ad-hoc route: the Albanese functor on smooth proper curves.
7	
8	\section{The Albanese construction}
9	
10	For a smooth proper curve $C$ over $k$, the Albanese variety is the universal abelian variety receiving a morphism from $C$.  Over an algebraically closed field this is classically identified with the connected component of the identity of the Picard scheme, but we construct it directly from symmetric powers.
11	
12	\subsection{Symmetric powers and the Abel--Jacobi map}
13	
14	Let $C^{(g)} = \operatorname{Sym}^g(C)$ be the $g$\textsuperscript{th} symmetric power of $C$ (the quotient of $C^g$ by the action of the symmetric group $S_g$).  It is a smooth proper scheme over $k$ of dimension $g$.  Fix a $k$-rational point $P_0 \in C(k)$.  The map
15	\[
16	  \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
17	  \sum_{i=1}^g [P_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g P_i - g P_0\bigr)
18	\]
19	is surjective and birational onto its image; its fibres are projective spaces (Brill--Noether--Riemann--Roch).  Choosing $P_0$ gives a translation isomorphism $\Pic^g_{C/k} \xrightarrow{\;\sim\;} \Pic^0_{C/k}$, and the Stein factorisation of $\sigma$ yields the Jacobian as the connected component of the identity.
20	
21	In the Lean formalisation we do not have general symmetric powers of schemes (or quotients by finite group actions) in Mathlib.  We therefore take a more direct approach: we define the Jacobian as the Albanese object of $C$ inside the category of smooth proper group schemes over $k$, using the universal property and the known dimension formula.
22	
23	\begin{definition}[Jacobian]
24	  \label{def:Jacobian}
25	  \lean{AlgebraicGeometry.Jacobian}
26	  \leanok
27	  \uses{def:genus}
28	  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$.  It is viewed as an object of $\textrm{Over}(\Spec k)$.
29	\end{definition}
30	
31	\section{Group scheme structure and abelian-variety properties}
32	
33	\begin{theorem}[Group object structure]
34	  \label{thm:Jacobian_grpObj}
35	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
36	  \leanok
37	  \uses{def:Jacobian}
38	  $\Jac(C)$ carries a canonical group-object structure in $\textrm{Over}(\Spec k)$, induced by the Albanese universal property and the cogroup structure of $C$ in the category of pointed curves.
39	\end{theorem}
40	
41	\begin{theorem}[Smoothness and dimension]
42	  \label{thm:Jacobian_smooth_genus}
43	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
44	  \leanok
45	  \uses{def:Jacobian, def:genus}
46	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
47	\end{theorem}
48	
49	\begin{theorem}[Properness]
50	  \label{thm:Jacobian_proper}
51	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
52	  \leanok
53	  \uses{def:Jacobian}
54	  $\Jac(C) \to \Spec k$ is proper.
55	\end{theorem}
56	
57	\begin{theorem}[Geometric irreducibility]
58	  \label{thm:Jacobian_geomIrred}
59	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
60	  \leanok
61	  \uses{def:Jacobian}
62	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
63	\end{theorem}
64	
65	\noindent All four properties are part of the Albanese construction.  Smoothness and dimension follow from the deformation-theoretic identification of the tangent space at the identity with $H^1(C, \mathcal O_C)$ (Phase~A, Chapter~\ref{chap:Cohomology_StructureSheafAb}).  Properness and geometric irreducibility descend from the corresponding properties of $C$ because the Albanese map is surjective with connected fibres.
66	
67	\subsection{Sanity check in low genus}
68	
69	\begin{itemize}
70	  \item $g = 0$: Then $\Jac(C) = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$.  The terminal object of $\textrm{Over}(\Spec k)$ already carries \lstinline{GrpObj} via \lstinline{instTensorUnit}.
71	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an abelian variety.
72	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
73	\end{itemize}
74	
75	\section{Implementation route in Lean}
76	
77	Because the full Picard-scheme representability theorem is not available in Mathlib, the formal construction proceeds in two layers:
78	
79	\begin{enumerate}
80	  \item \textbf{Layer I -- direct definition.}  Define \lstinline{Jacobian C} as an object of \lstinline{Over (Spec (.of k))} carrying the four instances above.  In the first instance the underlying scheme can be taken to be the terminal object \lstinline{⊤_ (Over (Spec (.of k)))} when the genus is $0$, and for higher genus it is built from an ad-hoc quotient of a suitable symmetric-power-like functor.  Since Mathlib lacks general quotients of schemes by finite group actions, we instead rely on the Albanese universal property: \lstinline{Jacobian C} is declared as the representing object of the Albanese functor for $C$.
81	
82	  \item \textbf{Layer II -- Abel--Jacobi compatibility.}  Chapter~\ref{chap:AbelJacobi} introduces the Abel--Jacobi morphism $C \to \Jac(C)$ and shows that it is universal among morphisms from $C$ to abelian varieties.  This is the content of the three protected sorries in \lstinline{AbelJacobi.lean}.
83	\end{enumerate}
84	
85	\noindent The five protected sorries in \lstinline{Jacobian.lean} (\lstinline{Jacobian}, \lstinline{instGrpObj}, \lstinline{smoothOfRelativeDimension_genus}, \lstinline{instIsProper}, \lstinline{instGeometricallyIrreducible}) and the three in \lstinline{AbelJacobi.lean} (\lstinline{ofCurve}, \lstinline{comp_ofCurve}, \lstinline{exists_unique_ofCurve_comp}) are now in active scope for the prover.  They are assigned to the Phase~C parallel track of \texttt{STRATEGY.md}.
